THRESHOLDS = {
 'cpu': 80, # Alert at 80% CPU usage
 'memory': 85, # Alert at 85% memory usage
 'disk': 90, # Alert at 90% disk usage
 'network': 75 # Alert at 75% bandwidth
}

def check_thresholds(metrics):
 """
 Check current metrics against thresholds
 Args: metrics dict with cpu, memory, disk, network values
 Returns: List of alerts
 """
 alerts = []
 for resource, usage in metrics.items():
 if resource in THRESHOLDS:
 threshold = THRESHOLDS[resource]
 if usage >= threshold:
 alerts.append(f"CRITICAL: {resource} at {usage}% (threshold: {threshold}%)")
 elif usage >= threshold * 0.9:
 alerts.append(f"WARNING: {resource} at {usage}% (threshold: {threshold}%)")
 return alerts

# Example
current_metrics = {'cpu': 82, 'memory': 60, 'disk': 45, 'network': 50}
alerts = check_thresholds(current_metrics)
for alert in alerts:
 print(alert)
